using System;

class SyntaxExamples {
    static void Main() {
        // var type inference
        var message = "Hello, C#";  // Compiler infers string
        var number = 42;  // Compiler infers int
        var list = new List<string>();  // Compiler infers List<string>

        // Nullable types
        string? nullableString = null;
        int? nullableInt = null;

        // Null-coalescing and null-conditional operators
        var name = nullableString ?? "Default Name";
        var length = nullableString?.Length ?? 0;

        // Pattern matching with switch expression
        object obj = "Hello";
        var result = obj switch {
            int i => $"Integer: {i}",
            string s when s.Length > 5 => $"Long string: {s}",
            string s => $"Short string: {s}",
            null => "Null value",
            _ => "Unknown type"
        };

        // Tuples
        var person = (Name: "Alice", Age: 30, City: "New York");
        Console.WriteLine($"Name: {person.Name}, Age: {person.Age}");

        // Tuple deconstruction
        (string name, int age) = person;

        // Local function with pattern matching
        bool IsValidPerson((string Name, int Age) p) {
            return p is { Name: not null, Age: >= 0 and <= 150 };
        }

        // Record example
        var employee = new Employee("John", "Developer");
        Console.WriteLine(employee);  // Auto-generated ToString()

        // Boxing and unboxing demonstration
        int value = 100;
        object boxed = value;  // Boxing
        int unboxed = (int)boxed;  // Unboxing

        // Ref local and return
        int[] numbers = { 1, 2, 3, 4, 5 };
        ref int found = ref Find(numbers, 3);
        found = 10;  // Modifies original array element
    }

    // Ref return method
    static ref int Find(int[] array, int value) {
        for (int i = 0; i < array.Length; i++) {
            if (array[i] == value) {
                return ref array[i];
            }
        }
        throw new ArgumentException("Value not found");
    }
}

