using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Threading;
using System.Threading.Tasks;

public class AsyncExamples
{
    // Basic async method
    public async Task<string> DownloadContentAsync(string url, CancellationToken cancellationToken = default)
    {
        using var httpClient = new HttpClient();

        try
        {
            // ConfigureAwait(false) for library code
            var response = await httpClient.GetAsync(url, cancellationToken).ConfigureAwait(false);
            response.EnsureSuccessStatusCode();
            return await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
        }
        catch (HttpRequestException ex)
        {
            Console.WriteLine($"HTTP Error: {ex.Message}");
            throw;
        }
    }

    // Parallel processing with Task.WhenAll
    public async Task<IEnumerable<string>> DownloadMultipleAsync(IEnumerable<string> urls)
    {
        var tasks = urls.Select(url => DownloadContentAsync(url));
        var results = await Task.WhenAll(tasks);
        return results;
    }

    // Timeout pattern
    public async Task<string> DownloadWithTimeoutAsync(string url, TimeSpan timeout)
    {
        using var cts = new CancellationTokenSource(timeout);

        try
        {
            return await DownloadContentAsync(url, cts.Token);
        }
        catch (TaskCanceledException) when (!cts.Token.IsCancellationRequested)
        {
            throw new TimeoutException($"Download timed out after {timeout.TotalSeconds} seconds");
        }
    }

    // ValueTask example for caching
    private string cachedData;
    private DateTime cacheTime;

    public ValueTask<string> GetCachedDataAsync(bool forceRefresh = false)
    {
        // Synchronous path - cache hit
        if (!forceRefresh && cachedData != null && DateTime.UtcNow - cacheTime < TimeSpan.FromMinutes(5))
        {
            return new ValueTask<string>(cachedData);
        }

        // Asynchronous path - need to fetch
        return new ValueTask<string>(FetchAndCacheDataAsync());
    }

    private async Task<string> FetchAndCacheDataAsync()
    {
        await Task.Delay(1000); // Simulate network delay
        cachedData = "Fresh data";
        cacheTime = DateTime.UtcNow;
        return cachedData;
    }

    // Async streams (C# 8+)
    public async IAsyncEnumerable<int> GenerateSequenceAsync(int start, int count, 
        [EnumeratorCancellation] CancellationToken cancellationToken = default)
    {
        for (int i = 0; i < count; i++)
        {
            cancellationToken.ThrowIfCancellationRequested();
            await Task.Delay(100, cancellationToken); // Simulate async work
            yield return start + i;
        }
    }

    // Progress reporting
    public async Task ProcessWithProgressAsync(IProgress<int> progress)
    {
        for (int i = 0; i <= 100; i += 10)
        {
            await Task.Delay(200);
            progress?.Report(i);
        }
    }

    // Exception handling in async
    public async Task<string> SafeOperationAsync()
    {
        try
        {
            return await RiskyOperationAsync();
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            // Log error but don't crash
            Console.WriteLine($"Error: {ex.Message}");
            return "Default value";
        }
    }

    private async Task<string> RiskyOperationAsync()
    {
        await Task.Delay(100);
        throw new InvalidOperationException("Something went wrong");
    }

    // TaskCompletionSource for event-based async
    public Task<string> WaitForUserInputAsync()
    {
        var tcs = new TaskCompletionSource<string>();

        // In real app, hook up to UI event
        Task.Run(async () =>
        {
            await Task.Delay(2000); // Simulate user thinking
            tcs.SetResult("User entered: Hello");
        });

        return tcs.Task;
    }

    // Async factory method pattern
    public class DataService
    {
        private DataService() { }

        public static async Task<DataService> CreateAsync(string connectionString)
        {
            var service = new DataService();
            await service.InitializeAsync(connectionString);
            return service;
        }

        private async Task InitializeAsync(string connectionString)
        {
            await Task.Delay(100); // Simulate async initialization
        }
    }

    // Using async with using declaration
    public async Task ProcessFileAsync(string path)
    {
        await using var fileStream = new FileStream(path, FileMode.Open);
        await using var reader = new StreamReader(fileStream);

        string content = await reader.ReadToEndAsync();
        Console.WriteLine(content);
    }
}

// Async console app entry point
class Program
{
    static async Task Main(string[] args)
    {
        var examples = new AsyncExamples();

        // Basic async call
        var data = await examples.DownloadContentAsync("https://example.com");
        Console.WriteLine($"Downloaded: {data.Length} characters");

        // Parallel downloads
        var urls = new[] { "https://example.com/1", "https://example.com/2" };
