        await foreach (var number in examples.GenerateSequenceAsync(1, 5))
        {
            Console.WriteLine($"Generated: {number}");
        }

        // Progress reporting
        var progress = new Progress<int>(percent => Console.WriteLine($"Progress: {percent}%"));
        await examples.ProcessWithProgressAsync(progress);

        // Cancellation example
        using var cts = new CancellationTokenSource();
        cts.CancelAfter(TimeSpan.FromSeconds(1));

        try
        {
            await examples.DownloadWithTimeoutAsync("https://example.com", TimeSpan.FromSeconds(5));
        }
