using System;
using System.Collections.Generic;
using System.Linq;

public class Person
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int Age { get; set; }
    public string City { get; set; }
    public decimal Salary { get; set; }
}

public class Order
{
    public int OrderId { get; set; }
    public int PersonId { get; set; }
    public decimal Amount { get; set; }
    public DateTime OrderDate { get; set; }
}

public class LinqExamples
{
    private List<Person> people = new()
    {
        new Person { Id = 1, Name = "Alice", Age = 25, City = "New York", Salary = 50000 },
        new Person { Id = 2, Name = "Bob", Age = 30, City = "Los Angeles", Salary = 60000 },
        new Person { Id = 3, Name = "Charlie", Age = 35, City = "New York", Salary = 70000 },
        new Person { Id = 4, Name = "David", Age = 40, City = "Chicago", Salary = 80000 },
        new Person { Id = 5, Name = "Eve", Age = 28, City = "Los Angeles", Salary = 55000 }
    };

    private List<Order> orders = new()
    {
        new Order { OrderId = 1, PersonId = 1, Amount = 100, OrderDate = new DateTime(2024, 1, 15) },
        new Order { OrderId = 2, PersonId = 1, Amount = 200, OrderDate = new DateTime(2024, 2, 20) },
        new Order { OrderId = 3, PersonId = 2, Amount = 150, OrderDate = new DateTime(2024, 1, 10) },
        new Order { OrderId = 4, PersonId = 3, Amount = 300, OrderDate = new DateTime(2024, 3, 5) }
    };

    public void DemonstrateBasicQueries()
    {
        // Filtering and Projection
        var adults = people.Where(p => p.Age >= 18);
        var adultNames = people
            .Where(p => p.Age >= 18)
            .Select(p => p.Name);

        // Anonymous types
        var personInfo = people
            .Select(p => new { p.Name, IsAdult = p.Age >= 18 });

        // Sorting
        var sortedByAge = people.OrderBy(p => p.Age);
        var sortedByNameThenAge = people
            .OrderBy(p => p.Name)
            .ThenByDescending(p => p.Age);

        // Aggregation
        var totalSalary = people.Sum(p => p.Salary);
        var averageAge = people.Average(p => p.Age);
        var maxSalary = people.Max(p => p.Salary);

        // Grouping
        var peopleByCity = people.GroupBy(p => p.City);
        foreach (var group in peopleByCity)
        {
            Console.WriteLine($"City: {group.Key}, Count: {group.Count()}");
        }

        // More complex grouping with aggregation
        var cityStats = people
            .GroupBy(p => p.City)
            .Select(g => new 
            { 
                City = g.Key, 
                Count = g.Count(),
                AvgSalary = g.Average(p => p.Salary),
                TotalSalary = g.Sum(p => p.Salary)
            });
    }

    public void DemonstrateJoins()
    {
        // Inner Join (method syntax)
        var innerJoin = people.Join(
            orders,
            person => person.Id,
            order => order.PersonId,
            (person, order) => new { person.Name, order.Amount });

        // Group Join (method syntax)
        var groupJoin = people.GroupJoin(
            orders,
            person => person.Id,
            order => order.PersonId,
            (person, personOrders) => new 
            { 
                person.Name, 
                TotalOrders = personOrders.Sum(o => o.Amount) 
            });

        // Left Join using GroupJoin and SelectMany
        var leftJoin = people.GroupJoin(
                orders,
                person => person.Id,
                order => order.PersonId,
                (person, personOrders) => new { person, personOrders })
            .SelectMany(
                x => x.personOrders.DefaultIfEmpty(),
                (x, order) => new 
                { 
                    x.person.Name, 
                    OrderAmount = order?.Amount ?? 0 
                });

        // Query syntax examples
        var querySyntaxJoin = from p in people
                              join o in orders on p.Id equals o.PersonId
                              select new { p.Name, o.Amount };

        var querySyntaxGroupJoin = from p in people
                                   join o in orders on p.Id equals o.PersonId into personOrders
                                   select new { p.Name, Orders = personOrders };
    }

    public void DemonstrateDeferredExecution()
    {
        Console.WriteLine("\n=== Deferred Execution Demo ===");

        var query = people.Where(p => 
        {
            Console.WriteLine($"Checking {p.Name}");
            return p.Age > 30;
        });

        Console.WriteLine("Query defined, not executed yet");

        // First enumeration - executes query
        var firstResult = query.FirstOrDefault();
        Console.WriteLine($"First result: {firstResult?.Name}");

        // Second enumeration - executes query again!
        var count = query.Count();
        Console.WriteLine($"Count: {count}");

        // Materialize to avoid multiple executions
        var materialized = query.ToList();
        Console.WriteLine($"Materialized count: {materialized.Count}");
    }

    public void DemonstratePerformanceOptimizations()
    {
        // Use Any() instead of Count() for existence checks
        bool hasAdults = people.Any(p => p.Age >= 18);  // Good - stops at first match
        bool hasAdultsBad = people.Count(p => p.Age >= 18) > 0;  // Bad - counts all

        // Use FirstOrDefault() with predicate
        var john = people.FirstOrDefault(p => p.Name == "John");  // Good
        var johnBad = people.Where(p => p.Name == "John").FirstOrDefault();  // Less optimal

        // Avoid multiple enumerations
        var expensiveQuery = people.Where(p => ExpensiveCheck(p));
        var materialized = expensiveQuery.ToList();  // Execute once

        // Use Take() and Skip() for paging
        int pageSize = 2, pageNumber = 1;
        var page = people
            .Skip(pageNumber * pageSize)
            .Take(pageSize)
            .ToList();
    }

    private bool ExpensiveCheck(Person p)
    {
        // Simulate expensive operation
        System.Threading.Thread.Sleep(10);
        return p.Age > 30;
    }

    public void DemonstrateSetOperations()
    {
        var list1 = new[] { 1, 2, 3, 4, 5 };
        var list2 = new[] { 4, 5, 6, 7, 8 };

        var union = list1.Union(list2);          // 1,2,3,4,5,6,7,8
        var intersect = list1.Intersect(list2);  // 4,5
        var except = list1.Except(list2);        // 1,2,3
        var distinct = list1.Concat(list2).Distinct();  // 1,2,3,4,5,6,7,8
    }

    public void DemonstrateAdvancedQueries()
    {
        // Let clause for intermediate results (query syntax)
        var queryWithLet = from p in people
                           let nameLength = p.Name.Length
                           where nameLength > 4
                           select new { p.Name, NameLength = nameLength };

        // Partitioning with TakeWhile/SkipWhile
        var numbers = new[] { 1, 2, 3, 4, 5, 1, 2, 3 };
        var takeWhile = numbers.TakeWhile(n => n < 4);  // 1,2,3
        var skipWhile = numbers.SkipWhile(n => n < 4);  // 4,5,1,2,3

        // Chunking (.NET 6+)
        var chunks = numbers.Chunk(3);  // [[1,2,3], [4,5,1], [2,3]]

        // Zip for pairing elements
        var names = new[] { "Alice", "Bob", "Charlie" };
        var ages = new[] { 25, 30, 35 };
        var zipped = names.Zip(ages, (name, age) => $"{name} is {age} years old");

        // Aggregate for custom aggregation
        var csv = people.Aggregate("", 
            (current, person) => current + (current == "" ? "" : ",") + person.Name);

        // SelectMany for flattening
        var allOrderAmounts = people
            .SelectMany(p => orders.Where(o => o.PersonId == p.Id), 
                       (p, o) => o.Amount);
    }
}

// IQueryable vs IEnumerable example (with EF Core simulation)
public class DatabaseContext
{
    // Simulating EF Core DbSet
    public IQueryable<Person> People => people.AsQueryable();
    private List<Person> people = new();

    public void DemonstrateIQueryable()
    {
        // IQueryable - builds expression tree, translated to SQL
        var queryableQuery = People
            .Where(p => p.Age > 18)
            .OrderBy(p => p.Name)
            .Select(p => new { p.Name, p.Age });

        // The query hasn't executed yet
        Console.WriteLine("IQueryable query defined");

        // Execution happens here (when materialized)
        var results = queryableQuery.ToList();

        // IEnumerable - executes in memory
        var enumerableQuery = people  // This is IEnumerable<Person>
            .Where(p => p.Age > 18)
            .OrderBy(p => p.Name)
            .Select(p => new { p.Name, p.Age })
            .ToList();  // Already executed
    }
}

class Program
{
    static void Main()
    {
        var examples = new LinqExamples();

        examples.DemonstrateBasicQueries();
        examples.DemonstrateJoins();
        examples.DemonstrateDeferredExecution();
        examples.DemonstratePerformanceOptimizations();
        examples.DemonstrateSetOperations();
        examples.DemonstrateAdvancedQueries();

        Console.WriteLine("\nAll LINQ examples completed!");
    }
}

