using System;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Collections.Immutable;
using System.Linq;

public class CollectionExamples
{
    public void DemonstrateBasicCollections()
    {
        // List<T> - most common collection
        var numbers = new List<int> { 1, 2, 3, 4, 5 };
        numbers.Add(6);
        numbers.Insert(0, 0);
        numbers.Remove(3);
        numbers.RemoveAt(0);

        Console.WriteLine($"List count: {numbers.Count}");
        Console.WriteLine($"List capacity: {numbers.Capacity}");

        // Dictionary<TKey, TValue>
        var employees = new Dictionary<int, string>
        {
            [101] = "Alice",
            [102] = "Bob",
            [103] = "Charlie"
        };

        employees.Add(104, "David");
        employees[105] = "Eve"; // Add or update

        // Safe access patterns
        if (employees.TryGetValue(103, out string name))
        {
            Console.WriteLine($"Employee 103: {name}");
        }

        // Remove with check
        if (employees.Remove(101))
        {
            Console.WriteLine("Removed employee 101");
        }

        // HashSet<T> for unique items
        var uniqueTags = new HashSet<string> { "C#", ".NET", "ASP.NET" };
        bool added = uniqueTags.Add("C#"); // Returns false (already exists)
        bool contains = uniqueTags.Contains(".NET");

        // Set operations
        var backendTags = new HashSet<string> { "C#", "Java", "Python" };
        var commonTags = new HashSet<string>(uniqueTags);
        commonTags.IntersectWith(backendTags);

        // Queue<T> and Stack<T>
        var queue = new Queue<string>();
        queue.Enqueue("Task1");
        queue.Enqueue("Task2");
        Console.WriteLine($"Next task: {queue.Peek()}");
        Console.WriteLine($"Processing: {queue.Dequeue()}");

        var stack = new Stack<string>();
        stack.Push("Call1");
        stack.Push("Call2");
        Console.WriteLine($"Current call: {stack.Pop()}");
    }

    public void DemonstrateConcurrentCollections()
    {
        // ConcurrentDictionary - thread-safe dictionary
        var cache = new ConcurrentDictionary<string, DateTime>();

        // Multiple threads can safely call these
        cache.TryAdd("user:1", DateTime.Now);
        cache.AddOrUpdate("user:1", DateTime.Now, (key, oldValue) => DateTime.Now);

        var value = cache.GetOrAdd("user:2", key => DateTime.Now.AddHours(1));

        // Iteration (snapshot)
        foreach (var item in cache)
        {
            Console.WriteLine($"{item.Key}: {item.Value}");
        }

        // ConcurrentQueue - thread-safe FIFO
        var messageQueue = new ConcurrentQueue<string>();

        // Producer
        messageQueue.Enqueue("Message 1");
        messageQueue.Enqueue("Message 2");

        // Consumer
        if (messageQueue.TryDequeue(out string message))
        {
            Console.WriteLine($"Processed: {message}");
        }

        // ConcurrentBag - unordered collection optimized for producer-consumer
        var workItems = new ConcurrentBag<int>();
        workItems.Add(1);
        workItems.Add(2);

        // Each thread tends to get its own items back
        if (workItems.TryTake(out int workItem))
        {
            Console.WriteLine($"Processing work item: {workItem}");
        }

        // BlockingCollection - bounded collection with blocking operations
        var boundedCollection = new BlockingCollection<int>(boundedCapacity: 5);

        // Producer thread
        Task.Run(() =>
        {
            for (int i = 0; i < 10; i++)
            {
                boundedCollection.Add(i); // Blocks if full
                Console.WriteLine($"Produced: {i}");
            }
            boundedCollection.CompleteAdding();
        });

        // Consumer thread
        Task.Run(() =>
        {
            foreach (var item in boundedCollection.GetConsumingEnumerable())
            {
                Console.WriteLine($"Consumed: {item}");
                Thread.Sleep(100); // Simulate work
            }
        });
    }

    public void DemonstrateImmutableCollections()
    {
        // Create immutable collections
        var immutableList = ImmutableList.Create(1, 2, 3);
        var newList = immutableList.Add(4).Add(5); // Returns new instance

        Console.WriteLine($"Original count: {immutableList.Count}");
        Console.WriteLine($"New count: {newList.Count}");

        // Immutable dictionary
        var config = ImmutableDictionary<string, string>.Empty
            .Add("ConnectionString", "Server=...")
            .Add("Timeout", "30")
            .SetItem("Timeout", "60"); // Update returns new instance

        // Immutable hash set
        var permissions = ImmutableHashSet.Create("Read", "Write", "Execute");
        var newPermissions = permissions.Add("Delete");

        // Builder pattern for multiple modifications
        var builder = immutableList.ToBuilder();
        builder.Add(6);
        builder.Remove(2);
        var modifiedList = builder.ToImmutable();

        // Thread-safe sharing
        Task.Run(() => Console.WriteLine($"Thread 1: {immutableList[0]}"));
        Task.Run(() => Console.WriteLine($"Thread 2: {immutableList[1]}"));
    }

    public void DemonstratePerformanceConsiderations()
    {
        // Pre-allocate capacity when size is known
        var largeList = new List<int>(capacity: 10000);

        // Choose right collection for operation frequency
        var frequentLookups = new Dictionary<int, string>(); // O(1) lookup
        var sortedData = new SortedDictionary<int, string>(); // O(log n) but ordered

        // Linked list for frequent insertions/deletions in middle
        var linkedList = new LinkedList<string>();
        var middleNode = linkedList.AddFirst("middle");
        linkedList.AddBefore(middleNode, "before");
        linkedList.AddAfter(middleNode, "after");

        // Array for fixed-size, high-performance scenarios
        int[] fixedArray = new int[100];
        Span<int> span = fixedArray.AsSpan();

        // Choose comparers wisely
        var caseSensitiveDict = new Dictionary<string, int>();
        var caseInsensitiveDict = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        // Custom equality comparer
        var personDict = new Dictionary<Person, string>(new PersonEqualityComparer());
    }

    public void DemonstrateSpecializedCollections()
    {
        // BitArray for compact boolean storage
        var bits = new BitArray(10);
        bits[0] = true;
        bits[1] = false;
        bits.Set(2, true);
        bits.Length = 20; // Resize

        // StringCollection (non-generic, legacy)
        var strings = new System.Collections.Specialized.StringCollection();
        strings.Add("item1");
        strings.Add("item2");

        // HybridDictionary (switches between ListDictionary and Hashtable)
        var hybrid = new System.Collections.Specialized.HybridDictionary();
        hybrid.Add("small", "collection");

        // OrderedDictionary (preserves insertion order)
        var ordered = new System.Collections.Specialized.OrderedDictionary();
        ordered.Add("first", 1);
        ordered.Add("second", 2);
    }
}

