[AttributeUsage(AttributeTargets.Property, AllowMultiple = false)]
public class NoProfanityAttribute : ValidationAttribute
{
    private static readonly string[] ProfanityList = { "badword1", "badword2", "badword3" };

    protected override ValidationResult IsValid(object value, ValidationContext validationContext)
    {
        if (value is string stringValue)
        {
            foreach (var word in ProfanityList)
            {
                if (stringValue.Contains(word, StringComparison.OrdinalIgnoreCase))
                {
                    return new ValidationResult($"{validationContext.DisplayName} contains inappropriate language.");
                }
            }
        }
        return ValidationResult.Success;
    }
