public class SecureFileOperations
{
    public static void SaveUploadedFile(IFormFile file, string uploadPath)
    {
        // Validate file size (max 10MB)
        const long maxFileSize = 10 * 1024 * 1024;
        if (file.Length > maxFileSize)
            throw new ArgumentException("File too large");

        // Validate file extension
        var allowedExtensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".pdf" };
        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
        if (!allowedExtensions.Contains(extension))
            throw new ArgumentException("Invalid file type");

        // Sanitize filename
        var fileName = Path.GetFileName(file.FileName);
        var sanitizedFileName = SanitizeFileName(fileName);

        // Ensure upload directory exists and is secure
        if (!Directory.Exists(uploadPath))
            Directory.CreateDirectory(uploadPath);

        // Set directory permissions if needed

        // Save file with a random name to prevent path traversal
        var randomFileName = Path.Combine(uploadPath, Path.GetRandomFileName() + extension);

        using var stream = new FileStream(randomFileName, FileMode.Create);
        file.CopyTo(stream);
    }

    private static string SanitizeFileName(string fileName)
    {
        // Remove path traversal attempts
        fileName = fileName.Replace("..", string.Empty)
                          .Replace("/", string.Empty)
                          .Replace("\\", string.Empty);

        // Remove control characters
        fileName = Regex.Replace(fileName, @"[\x00-\x1F\x7F]", string.Empty);

        return fileName;
    }
}

