    {
        byte[] randomBytes = RandomNumberGenerator.GetBytes(length);
        return Convert.ToBase64String(randomBytes)
            .Replace("+", "-")
            .Replace("/", "_")
            .Replace("=", ""); // URL-safe base64
    }

    public static int GenerateSecureRandomNumber(int minValue, int maxValue)
    {
        if (minValue >= maxValue)
            throw new ArgumentException("minValue must be less than maxValue");

        // Generate random bytes
        byte[] randomBytes = RandomNumberGenerator.GetBytes(4);
        uint randomNumber = BitConverter.ToUInt32(randomBytes, 0);

        // Scale to desired range
        int range = maxValue - minValue;
        return (int)(randomNumber % range) + minValue;
    }
}

// Example 8: Encryption and decryption
public class SecureEncryption
{
    public static (string Encrypted, string IV) Encrypt(string plainText, byte[] key)
    {
        using var aes = Aes.Create();
        aes.Key = key;
        aes.GenerateIV();

        using var encryptor = aes.CreateEncryptor();
        using var ms = new System.IO.MemoryStream();
        using var cs = new CryptoStream(ms, encryptor, CryptoStreamMode.Write);

        byte[] plainBytes = Encoding.UTF8.GetBytes(plainText);
        cs.Write(plainBytes, 0, plainBytes.Length);
        cs.FlushFinalBlock();

        byte[] encryptedBytes = ms.ToArray();
        return (Convert.ToBase64String(encryptedBytes), Convert.ToBase64String(aes.IV));
    }

    public static string Decrypt(string encryptedText, byte[] key, string iv)
    {
        byte[] encryptedBytes = Convert.FromBase64String(encryptedText);
        byte[] ivBytes = Convert.FromBase64String(iv);

        using var aes = Aes.Create();
        aes.Key = key;
        aes.IV = ivBytes;

        using var decryptor = aes.CreateDecryptor();
        using var ms = new System.IO.MemoryStream(encryptedBytes);
        using var cs = new CryptoStream(ms, decryptor, CryptoStreamMode.Read);
        using var sr = new System.IO.StreamReader(cs);

        return sr.ReadToEnd();
    }
}

// Example 9: JWT token handling
public class JwtSecurity
{
    public static string GenerateJwtToken(string userId, string username, string[] roles, string secretKey)
    {
        var tokenHandler = new System.IdentityModel.Tokens.Jwt.JwtSecurityTokenHandler();
        var key = Encoding.ASCII.GetBytes(secretKey);

        var tokenDescriptor = new SecurityTokenDescriptor
        {
            Subject = new ClaimsIdentity(new[]
            {
                new Claim(ClaimTypes.NameIdentifier, userId),
                new Claim(ClaimTypes.Name, username),
                new Claim(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString())
            }),
            Expires = DateTime.UtcNow.AddHours(2),
            SigningCredentials = new SigningCredentials(
                new SymmetricSecurityKey(key),
                SecurityAlgorithms.HmacSha256Signature)
        };

        // Add roles if any
        foreach (var role in roles)
        {
            tokenDescriptor.Subject.AddClaim(new Claim(ClaimTypes.Role, role));
        }

        var token = tokenHandler.CreateToken(tokenDescriptor);
        return tokenHandler.WriteToken(token);
    }

    public static ClaimsPrincipal ValidateJwtToken(string token, string secretKey)
    {
        var tokenHandler = new System.IdentityModel.Tokens.Jwt.JwtSecurityTokenHandler();
        var key = Encoding.ASCII.GetBytes(secretKey);

        try
        {
            var validationParameters = new TokenValidationParameters
            {
                ValidateIssuerSigningKey = true,
                IssuerSigningKey = new SymmetricSecurityKey(key),
                ValidateIssuer = false,
                ValidateAudience = false,
                ValidateLifetime = true,
                ClockSkew = TimeSpan.Zero // No tolerance for expired tokens
            };

            var principal = tokenHandler.ValidateToken(token, validationParameters, out _);
            return principal;
        }
        catch
        {
            return null;
        }
    }
}

