// Strategy Pattern Implementation
public interface IPaymentStrategy
{
    Task<PaymentResult> ProcessAsync(decimal amount);
}

public class CreditCardPayment : IPaymentStrategy
{
    public async Task<PaymentResult> ProcessAsync(decimal amount)
    {
        // Process credit card payment
        return new PaymentResult { Success = true };
    }
}

public class PayPalPayment : IPaymentStrategy
{
    public async Task<PaymentResult> ProcessAsync(decimal amount)
    {
        // Process PayPal payment
        return new PaymentResult { Success = true };
    }
}

public class PaymentContext
{
    private IPaymentStrategy _strategy;

    public void SetStrategy(IPaymentStrategy strategy) => _strategy = strategy;

    public async Task<PaymentResult> ExecutePaymentAsync(decimal amount)
        => await _strategy.ProcessAsync(amount);
}

// Factory Pattern for strategy creation
public class PaymentStrategyFactory
{
    private readonly IServiceProvider _serviceProvider;
    public PaymentStrategyFactory(IServiceProvider serviceProvider) 
        => _serviceProvider = serviceProvider;

    public IPaymentStrategy Create(string paymentMethod)
    {
        return paymentMethod switch
        {
            "creditcard" => _serviceProvider.GetRequiredService<CreditCardPayment>(),
            "paypal" => _serviceProvider.GetRequiredService<PayPalPayment>(),
            _ => throw new ArgumentException("Invalid payment method")
        };
    }
}

// Observer Pattern with Events
public class Order
{
    public event EventHandler<OrderEventArgs>? OrderPlaced;
    public event EventHandler<OrderEventArgs>? OrderShipped;

    public void PlaceOrder()
    {
        // Order placement logic
        OnOrderPlaced(new OrderEventArgs(this));
    }

    protected virtual void OnOrderPlaced(OrderEventArgs e)
        => OrderPlaced?.Invoke(this, e);
}

// Reactive Extensions (Rx.NET) Implementation
public class StockMonitor
{
    private readonly Subject<StockTick> _stockTicks = new();
    public IObservable<StockTick> WhenStockTick => _stockTicks.AsObservable();

    public void UpdateStock(StockTick tick) => _stockTicks.OnNext(tick);
}

// Usage with filtering and buffering
var monitor = new StockMonitor();
monitor.WhenStockTick
    .Where(tick => tick.Price > 100)
    .Buffer(TimeSpan.FromSeconds(5))
    .Subscribe(ticks => Console.WriteLine($"High value ticks: {ticks.Count}"));

// MediatR Pipeline Behavior for Cross-Cutting Concerns
public class LoggingBehavior<TRequest, TResponse> 
    : IPipelineBehavior<TRequest, TResponse>
    where TRequest : IRequest<TResponse>
{
    private readonly ILogger<LoggingBehavior<TRequest, TResponse>> _logger;

    public LoggingBehavior(ILogger<LoggingBehavior<TRequest, TResponse>> logger) 
        => _logger = logger;

    public async Task<TResponse> Handle(
        TRequest request,
        RequestHandlerDelegate<TResponse> next,
        CancellationToken ct)
    {
        _logger.LogInformation("Handling {Request}", typeof(TRequest).Name);
        var response = await next();
        _logger.LogInformation("Handled {Request}", typeof(TRequest).Name);
        return response;
    }
}
